        # Check if the params are a list and not empty
        if not isinstance(params, list) or len(params) == 0:
            raise ValueError('Params must be a non-empty list')
        
        # Execute the script using redis.eval() with the given parameters
        result = self.client.eval(script, params=params)
        
        # Return the result of the script execution
